mapper.select:
select stat_id, stat_date, stat_type, warehouse_id, area_id, location_id,
       product_id, customer_id, sales_user_id, in_quantity, out_quantity, create_time
from wms_stock_statistics

    and stat_type = #{statType}
    and stat_date = #{statDate}
    and stat_date >= #{beginTime}
    and stat_date <= #{endTime}
    and warehouse_id = #{warehouseId}
    and product_id = #{productId}

order by stat_date desc
